import React, { useState, useEffect, useRef, useCallback } from 'react';
import './App.css';
import Header from './components/Header';
import Track from './components/Track';
import BetPanel from './components/BetPanel';
import { ChickenData, GamePhase } from './types';

const CHICKEN_CONFIGS = [
  { id: 1, name: 'Snow White',   bodyColor: '#f5f5f5', color: 'white' },
  { id: 2, name: 'Dark Knight',  bodyColor: '#2a2a2a', color: 'black' },
  { id: 3, name: 'Ash Gray',     bodyColor: '#555555', color: 'darkgray' },
  { id: 4, name: 'Silver Belle', bodyColor: '#cccccc', color: 'lightgray' },
];

const BASE_SPEED = 12;   // units per second
const VARIANCE    = 8;   // random extra per second

function createInitialChickens(): ChickenData[] {
  return CHICKEN_CONFIGS.map(cfg => ({
    ...cfg,
    position: 0,
    speed: BASE_SPEED + Math.random() * 4,
    finished: false,
  }));
}

const App: React.FC = () => {
  const [phase, setPhase]               = useState<GamePhase>('betting');
  const [chickens, setChickens]         = useState<ChickenData[]>(createInitialChickens);
  const [selectedChicken, setSelected]  = useState<number | null>(null);
  const [betAmount, setBetAmount]       = useState(100);
  const [balance, setBalance]           = useState(10_000_000);
  const [winner, setWinner]             = useState<number | null>(null);
  const [countdown, setCountdown]       = useState(3);
  const [resultMessage, setResultMsg]   = useState('');

  // Refs for animation loop
  const rafRef          = useRef<number | null>(null);
  const lastTimeRef     = useRef<number>(0);
  const chickensRef     = useRef<ChickenData[]>(chickens);
  const phaseRef        = useRef<GamePhase>(phase);
  const winnerRef       = useRef<number | null>(null);

  // Keep refs in sync
  useEffect(() => { chickensRef.current = chickens; }, [chickens]);
  useEffect(() => { phaseRef.current = phase; },       [phase]);

  // ─── Animation loop ──────────────────────────────────────────────────────────
  const tick = useCallback((timestamp: number) => {
    if (phaseRef.current !== 'racing') return;

    const delta = lastTimeRef.current
      ? (timestamp - lastTimeRef.current) / 1000
      : 0.016;
    lastTimeRef.current = timestamp;

    let newWinner: number | null = null;

    const updated = chickensRef.current.map(c => {
      if (c.finished) return c;
      const advance = (c.speed + Math.random() * VARIANCE) * delta;
      const newPos  = Math.min(100, c.position + advance);
      const finished = newPos >= 100;
      if (finished && winnerRef.current === null) {
        newWinner = c.id;
        winnerRef.current = c.id;
      }
      return { ...c, position: newPos, finished };
    });

    setChickens(updated);

    if (newWinner !== null) {
      // Race done
      setWinner(newWinner);
      setPhase('result');
      phaseRef.current = 'result';

      // Bet was already deducted at race start.
      // On win: add full payout (3.5x bet). Net gain = 2.5x bet.
      // On loss: balance already reduced, nothing more to do.
      if (selectedChickenRef.current !== null) {
        if (selectedChickenRef.current === newWinner) {
          const payout = Math.floor(betAmountRef.current * 3.5);
          setResultMsg(`🎉 You Win! +${Math.floor(betAmountRef.current * 2.5).toLocaleString()} $`);
          setBalance(prev => prev + payout);
        } else {
          setResultMsg(`😢 You Lose! -${betAmountRef.current.toLocaleString()} $`);
          // balance already reduced at start, no additional change
        }
      } else {
        setResultMsg('');
      }

      // Reset after 3s
      setTimeout(() => {
        setPhase('betting');
        phaseRef.current = 'betting';
        setChickens(createInitialChickens());
        setSelected(null);
        setWinner(null);
        winnerRef.current = null;
        setResultMsg('');
      }, 4000);

      return; // don't request next frame
    }

    rafRef.current = requestAnimationFrame(tick);
  }, []); // tick uses refs so no deps needed

  // Extra refs for closures
  const selectedChickenRef = useRef<number | null>(null);
  const betAmountRef        = useRef<number>(betAmount);
  useEffect(() => { selectedChickenRef.current = selectedChicken; }, [selectedChicken]);
  useEffect(() => { betAmountRef.current = betAmount; },             [betAmount]);

  // ─── Countdown → race ────────────────────────────────────────────────────────
  const startCountdown = useCallback(() => {
    setPhase('countdown');
    phaseRef.current = 'countdown';
    setCountdown(3);

    let count = 3;
    const interval = setInterval(() => {
      count--;
      if (count <= 0) {
        clearInterval(interval);
        setPhase('racing');
        phaseRef.current = 'racing';
        lastTimeRef.current = 0;
        rafRef.current = requestAnimationFrame(tick);
      } else {
        setCountdown(count);
      }
    }, 1000);
  }, [tick]);

  // Stop animation when unmounting
  useEffect(() => {
    return () => {
      if (rafRef.current) cancelAnimationFrame(rafRef.current);
    };
  }, []);

  // ─── Handlers ────────────────────────────────────────────────────────────────
  const handleSelectChicken = (id: number) => {
    if (phase !== 'betting') return;
    setSelected(id);
  };

  const handleRandomChoice = () => {
    if (phase !== 'betting' && phase !== 'result') return;
    const id = Math.floor(Math.random() * 4) + 1;
    setSelected(id);
    if (phase === 'result') return;
    // Auto-start if in betting
  };

  const handleStartRace = () => {
    if (phase !== 'betting') return;
    // Deduct bet now
    setBalance(prev => prev - betAmountRef.current);
    startCountdown();
  };

  return (
    <div className="app">
      <Header balance={balance} />
      <Track
        chickens={chickens}
        phase={phase}
        winner={winner}
        selectedChicken={selectedChicken}
        countdownValue={countdown}
      />
      <BetPanel
        betAmount={betAmount}
        selectedChicken={selectedChicken}
        phase={phase}
        balance={balance}
        onBetChange={setBetAmount}
        onSelectChicken={handleSelectChicken}
        onRandomChoice={handleRandomChoice}
        onStartRace={handleStartRace}
        winner={winner}
        resultMessage={resultMessage}
      />
    </div>
  );
};

export default App;
